	if (bid >= count) return;

	int threadsPerBlock = (order < 1024) ? order : 1024;

	for (int i = 0; i < maxheight; i++) {
		long curr = currKnode[bid];
		long last = lastKnode[bid];
		long off = offset[bid];
		long off2 = offset_2[bid];
		for (int thid = threadIdx.x; thid < threadsPerBlock; thid += blockDim.x) {
			int key_curr_left = knodes[curr].keys[thid];
			int key_curr_right = knodes[curr].keys[thid + 1];
			if (key_curr_left <= start[bid] && start[bid] < key_curr_right) {
				if (knodes_elem > knodes[curr].indices[thid]) {
					off = knodes[curr].indices[thid];
				}
			}
			int key_last_left = knodes[last].keys[thid];
			int key_last_right = knodes[last].keys[thid + 1];
			if (end[bid] >= key_last_left && end[bid] < key_last_right) {
				if (knodes_elem > knodes[last].indices[thid]) {
